// Переменные состояния
let currentOriginalWord = "";
let usedWords = JSON.parse(localStorage.getItem('usedWords')) || [];

// Элементы DOM
const wordDisplay = document.querySelector('.word');
const btnShow = document.querySelector('.open-word');
const btnNext = document.querySelector('.next-word');
const btnReset = document.querySelector('.cancel');

// 1. Функция перемешивания букв
function shuffleWord(text) {
    // Розбиваємо текст на масив слів (за пробілом)
    return text.split(' ').map(word => {
        if (word.length <= 1) return word;

        let letters = word.toLowerCase().split('');
        // Перемішуємо букви конкретного слова (Алгоритм Фішера-Єйтса)
        for (let i = letters.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [letters[i], letters[j]] = [letters[j], letters[i]];
        }
        return letters.join('');
    }).join(' '); // Збираємо слова назад у речення з пробілами
}

// 2. Получение текущих настроек сложности и темы
function getSettings() {
    const level = document.querySelector('input[name="level"]:checked').value; // easy, medium, hard
    const selectedThemes = Array.from(document.querySelectorAll('input[name="theme"]:checked')).map(cb => cb.value);
    return { level, selectedThemes };
}

// 3. Главная функция выбора нового слова
function pickNewWord() {
    const { level, selectedThemes } = getSettings();
    
    if (selectedThemes.length === 0) {
        wordDisplay.textContent = "Обери тему!";
        return;
    }

    // Собираем все доступные слова из выбранных тем и сложности
    let pool = [];
    selectedThemes.forEach(theme => {
        if (wordBank[theme] && wordBank[theme][level]) {
            pool = pool.concat(wordBank[theme][level]);
        }
    });

    // Фильтруем те, что уже были
    let availableWords = pool.filter(w => !usedWords.includes(w));

    // Если слова кончились
    if (availableWords.length === 0) {
        wordDisplay.textContent = "Слова закінчились!";
        return;
    }

    // Выбираем случайное слово
    currentOriginalWord = availableWords[Math.floor(Math.random() * availableWords.length)];
    
    renderWord(currentOriginalWord, level);
}

// 4. Отрисовка слова в зависимости от сложности
function renderWord(word, level) {
    // 1. Отримуємо запутанний текст, де пробіли на місцях
    const scrambledText = shuffleWord(word);
    const firstLetterChar = word.charAt(0).toLowerCase();

    if (level === 'easy') {
        let highlighted = false;
        let htmlResult = "";

        // Проходимо по кожному символу запутанного тексту
        for (let char of scrambledText) {
            // Шукаємо першу букву ОРИГІНАЛЬНОГО слова
            if (!highlighted && char.toLowerCase() === firstLetterChar) {
                htmlResult += `<span style="color: #a42424">${char}</span>`;
                highlighted = true; 
            } else {
                htmlResult += char;
            }
        }
        wordDisplay.innerHTML = htmlResult;
    } else {
        // Для середнього та складного рівнів просто виводимо маленькими буквами
        wordDisplay.textContent = scrambledText.toLowerCase();
    }
}

// --- Обработчики событий ---

// Кнопка "Следующее слово"
btnNext.addEventListener('click', () => {
    if (currentOriginalWord) {
        usedWords.push(currentOriginalWord);
        localStorage.setItem('usedWords', JSON.stringify(usedWords));
    }
    pickNewWord();
});

// Кнопка "Показать слово"
btnShow.addEventListener('click', () => {
    if (currentOriginalWord) {
        wordDisplay.textContent = currentOriginalWord; // Подсвечиваем, что это разгадка
        
    }
});

// Кнопка "Сбросить прогресс"
btnReset.addEventListener('click', () => {
    usedWords = [];
    localStorage.removeItem('usedWords');
    wordDisplay.textContent = "Прогрес скинуто";
    currentOriginalWord = "";
});

// Инициализация при первом запуске
wordDisplay.textContent = "Букви заплуталися!";
